//! Basic usage example for bids-rust
//! 
//! This example demonstrates how to:
//! - Load a BIDS dataset
//! - Search for specific files
//! - Read event and metadata files
//! - Check BIDS compliance

use bids_rust::{BidsProject, EventData, SidecarData, ComplianceChecker};
use std::env;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line or use example
    let args: Vec<String> = env::args().collect();
    let dataset_path = if args.len() > 1 {
        Path::new(&args[1])
    } else {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("Using example dataset path...");
        Path::new("./example_dataset")
    };

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = match BidsProject::new(dataset_path) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("Error loading dataset: {}", e);
            eprintln!("Make sure the path points to a valid BIDS dataset with dataset_description.json");
            return Err(e.into());
        }
    };

    // Display basic information
    println!("\n=== Dataset Information ===");
    println!("Name: {}", project.name);
    println!("BIDS Version: {}", project.bids_version);
    println!("Has sessions: {}", project.has_sessions);
    println!("Has derivatives: {}", project.has_derivatives);

    // Get dataset summary
    let summary = project.summary();
    println!("\n=== Dataset Summary ===");
    println!("Participants: {}", summary.n_participants);
    println!("Sessions: {}", summary.n_sessions);
    println!("Tasks: {:?}", summary.tasks);
    println!("Modalities: {:?}", summary.modalities);

    // List participants
    let participants = project.participants();
    println!("\n=== Participants ===");
    for (i, participant) in participants.iter().enumerate() {
        if i < 5 {
            print!("sub-{} ", participant);
        } else if i == 5 {
            print!("... ({} more)", participants.len() - 5);
            break;
        }
    }
    println!();

    // Search for functional scans
    println!("\n=== Functional Scans ===");
    let func_scans = project.func_scans()?;
    println!("Found {} functional scans", func_scans.len());

    // Show first few scans
    for (i, scan) in func_scans.iter().enumerate() {
        if i >= 3 {
            println!("  ... and {} more", func_scans.len() - 3);
            break;
        }
        println!("  {}", scan.to_filename());
    }

    // Search for specific files
    if let Some(first_participant) = participants.first() {
        println!("\n=== Files for sub-{} ===", first_participant);

        let participant_files = project.search_files()
            .subject(first_participant)
            .execute()?;

        println!("Found {} files", participant_files.len());

        // Group by suffix
        let mut by_suffix = std::collections::HashMap::new();
        for file in &participant_files {
            by_suffix.entry(&file.suffix).or_insert(0u32);
            *by_suffix.get_mut(&file.suffix).unwrap() += 1;
        }

        for (suffix, count) in by_suffix {
            println!("  {}: {} files", suffix, count);
        }
    }

    // Read event files if available
    println!("\n=== Event Files ===");
    let event_files = project.search_files()
        .suffix("events")
        .extension("tsv")
        .execute()?;

    if event_files.is_empty() {
        println!("No event files found");
    } else {
        println!("Found {} event files", event_files.len());

        // Read first event file
        if let Some(event_file) = event_files.first() {
            if let Some(path) = &event_file.path {
                println!("\nReading: {}", event_file.to_filename());
                let events = EventData::read(path)?;

                println!("  Number of events: {}", events.onset.len());

                // Get unique trial types
                let unique_trials: std::collections::HashSet<_> = 
                    events.trial_type.iter().collect();
                println!("  Trial types: {:?}", unique_trials);

                // Show first few events
                println!("  First events:");
                for i in 0..3.min(events.onset.len()) {
                    println!("    {:.2}s: {} (duration: {:.2}s)", 
                        events.onset[i], 
                        events.trial_type[i],
                        events.duration[i]
                    );
                }
            }
        }
    }

    // Read JSON metadata
    println!("\n=== Metadata (JSON Sidecars) ===");
    let json_files = project.search_files()
        .suffix("bold")
        .extension("json")
        .execute()?;

    if json_files.is_empty() {
        println!("No JSON sidecar files found");
    } else {
        println!("Found {} JSON files", json_files.len());

        // Read first JSON file
        if let Some(json_file) = json_files.first() {
            if let Some(path) = &json_file.path {
                println!("\nReading: {}", json_file.to_filename());
                let sidecar = SidecarData::read(path)?;

                if let Some(tr) = sidecar.repetition_time() {
                    println!("  Repetition Time: {}s", tr);
                }
                if let Some(task) = sidecar.task_name() {
                    println!("  Task Name: {}", task);
                }
                if let Some(te) = sidecar.echo_time() {
                    println!("  Echo Time: {}ms", te * 1000.0);
                }
            }
        }
    }

    // Check BIDS compliance
    println!("\n=== BIDS Compliance Check ===");
    let checker = ComplianceChecker::new(&project);
    let compliance = checker.check_compliance()?;

    println!("BIDS Compliant: {}", if compliance.is_valid { "✓ Yes" } else { "✗ No" });

    // Count issues by severity
    let mut errors = 0;
    let mut warnings = 0;
    let mut info = 0;

    for issue in &compliance.issues {
        match issue.severity {
            bids_rust::ComplianceSeverity::Error => errors += 1,
            bids_rust::ComplianceSeverity::Warning => warnings += 1,
            bids_rust::ComplianceSeverity::Info => info += 1,
        }
    }

    if errors > 0 || warnings > 0 || info > 0 {
        println!("Issues found:");
        if errors > 0 {
            println!("  Errors: {}", errors);
        }
        if warnings > 0 {
            println!("  Warnings: {}", warnings);
        }
        if info > 0 {
            println!("  Info: {}", info);
        }

        // Show first few issues
        println!("\nFirst issues:");
        for (i, issue) in compliance.issues.iter().enumerate() {
            if i >= 3 {
                println!("  ... and {} more", compliance.issues.len() - 3);
                break;
            }
            println!("  {:?}: {}", issue.severity, issue.description);
        }
    } else {
        println!("No compliance issues found!");
    }

    Ok(())
}

