//! Comprehensive example of using the BIDS search API
//! 
//! This example demonstrates various search patterns and use cases:
//! - Basic searches by modality and suffix
//! - Complex searches with multiple filters
//! - Entity-based filtering
//! - Regex patterns
//! - Excluding files
//! - Working with derivatives

use bids_rust::{BidsProject, BidsFile};
use std::env;
use std::path::Path;
use std::collections::HashMap;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line
    let args: Vec<String> = env::args().collect();
    let dataset_path = if args.len() > 1 {
        Path::new(&args[1])
    } else {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("Using example dataset path...");
        Path::new("./example_dataset")
    };

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = match BidsProject::new(dataset_path) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("Error loading dataset: {}", e);
            return Err(e.into());
        }
    };

    println!("Dataset: {}", project.name);
    println!("Participants: {}", project.participants().len());
    println!();

    // Example 1: Basic search by suffix
    println!("=== Example 1: Find all T1w images ===");
    let t1w_files = project.search_files()
        .suffix("T1w")
        .execute()?;

    println!("Found {} T1w images", t1w_files.len());
    print_first_n(&t1w_files, 3);

    // Example 2: Search with multiple filters
    println!("\n=== Example 2: Find functional scans for specific task ===");
    let task_files = project.search_files()
        .suffix("bold")
        .task("rest")  // Change to your task name
        .extension("nii.gz")
        .execute()?;

    println!("Found {} resting-state scans", task_files.len());
    print_first_n(&task_files, 3);

    // Example 3: Search by participant
    if let Some(first_sub) = project.participants().first() {
        println!("\n=== Example 3: All files for participant {} ===", first_sub);
        let sub_files = project.search_files()
            .subject(first_sub)
            .execute()?;

        println!("Found {} files", sub_files.len());

        // Group by modality
        let by_modality = group_by_modality(&sub_files);
        for (modality, count) in by_modality {
            println!("  {}: {} files", modality, count);
        }
    }

    // Example 4: Complex entity search
    println!("\n=== Example 4: Complex entity search ===");
    let complex_search = project.search_files()
        .entity("datatype", "func")
        .entity("run", "01")
        .suffix("bold")
        .execute()?;

    println!("Found {} files matching complex criteria", complex_search.len());
    print_first_n(&complex_search, 3);

    // Example 5: Search with regex patterns
    println!("\n=== Example 5: Regex pattern search ===");
    let regex_files = project.search_files()
        .regex("sub-\\d{2}_.*_bold")
        .execute()?;

    println!("Found {} files matching regex pattern", regex_files.len());
    print_first_n(&regex_files, 3);

    // Example 6: Exclude specific files
    println!("\n=== Example 6: Search with exclusions ===");
    let filtered_files = project.search_files()
        .suffix("bold")
        .exclude_suffix("sbref")
        .execute()?;

    println!("Found {} BOLD files (excluding sbref)", filtered_files.len());

    // Example 7: Find all event files
    println!("\n=== Example 7: Find event files ===");
    let event_files = project.search_files()
        .suffix("events")
        .extension("tsv")
        .execute()?;

    println!("Found {} event files", event_files.len());

    // Show unique tasks from event files
    let unique_tasks: std::collections::HashSet<_> = event_files.iter()
        .filter_map(|f| f.task.as_ref())
        .collect();

    if !unique_tasks.is_empty() {
        println!("Tasks with events: {:?}", unique_tasks);
    }

    // Example 8: Find JSON sidecars
    println!("\n=== Example 8: Find JSON metadata files ===");
    let json_files = project.search_files()
        .extension("json")
        .execute()?;

    println!("Found {} JSON files", json_files.len());

    // Group by suffix
    let mut json_by_suffix: HashMap<&str, u32> = HashMap::new();
    for file in &json_files {
        *json_by_suffix.entry(&file.suffix).or_insert(0) += 1;
    }

    for (suffix, count) in json_by_suffix {
        println!("  {}: {} files", suffix, count);
    }

    // Example 9: Working with derivatives
    if project.has_derivatives {
        println!("\n=== Example 9: Search in derivatives ===");
        let derivative_files = project.search_files()
            .in_derivatives(true)
            .suffix("preproc")
            .execute()?;

        println!("Found {} preprocessed files in derivatives", derivative_files.len());
        print_first_n(&derivative_files, 3);

        // Find confound files
        let confound_files = project.search_files()
            .entity("desc", "confounds")
            .suffix("timeseries")
            .execute()?;

        println!("\nFound {} confound files", confound_files.len());
    }

    // Example 10: Combine multiple search criteria
    println!("\n=== Example 10: Advanced combined search ===");
    let advanced_search = project.search_files()
        .datatype("func")
        .suffix("bold")
        .task("rest")
        .run("01")
        .extension("nii.gz")
        .execute()?;

    println!("Found {} files matching all criteria", advanced_search.len());

    // Show the full path of matching files
    for (i, file) in advanced_search.iter().enumerate() {
        if i >= 3 {
            println!("  ... and {} more", advanced_search.len() - 3);
            break;
        }
        if let Some(path) = &file.path {
            println!("  {}", path.display());
        }
    }

    // Example 11: Search and then filter results
    println!("\n=== Example 11: Post-search filtering ===");
    let all_func = project.search_files()
        .datatype("func")
        .execute()?;

    // Filter in memory for specific criteria
    let filtered: Vec<_> = all_func.iter()
        .filter(|f| f.run.as_ref().map_or(false, |r| r == "01" || r == "02"))
        .filter(|f| f.suffix == "bold")
        .collect();

    println!("Found {} functional files, {} match run 01 or 02", 
        all_func.len(), filtered.len());

    Ok(())
}

/// Helper function to print first N files
fn print_first_n(files: &[BidsFile], n: usize) {
    for (i, file) in files.iter().enumerate() {
        if i >= n {
            if files.len() > n {
                println!("  ... and {} more", files.len() - n);
            }
            break;
        }
        println!("  {}", file.to_filename());
    }
}

/// Group files by modality (datatype)
fn group_by_modality(files: &[BidsFile]) -> HashMap<&str, u32> {
    let mut modalities = HashMap::new();
    for file in files {
        if let Some(datatype) = &file.datatype {
            *modalities.entry(datatype.as_str()).or_insert(0) += 1;
        }
    }
    modalities
}

