//! Example of working with BIDS derivatives (fMRIPrep outputs)
//! 
//! This example demonstrates how to:
//! - Access derivative datasets
//! - Find preprocessed images
//! - Read confound files
//! - Work with brain masks
//! - Access transformation files

use bids_rust::{BidsProject, ConfoundsData, SidecarData};
use std::env;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line
    let args: Vec<String> = env::args().collect();
    let dataset_path = if args.len() > 1 {
        Path::new(&args[1])
    } else {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("\nThis example requires a dataset with fMRIPrep derivatives");
        return Ok(());
    };

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = BidsProject::new(dataset_path)?;

    // Check for derivatives
    if !project.has_derivatives {
        eprintln!("No derivatives found in this dataset!");
        eprintln!("This example requires a dataset processed with fMRIPrep or similar");
        return Ok(());
    }

    println!("Dataset: {}", project.name);
    println!("Has derivatives: ✓");
    println!();

    // Example 1: Find preprocessed functional images
    println!("=== Example 1: Preprocessed functional images ===");
    let preproc_bold = project.search_files()
        .in_derivatives(true)
        .suffix("preproc")
        .desc("preproc")
        .datatype("func")
        .extension("nii.gz")
        .execute()?;

    println!("Found {} preprocessed BOLD images", preproc_bold.len());
    for (i, file) in preproc_bold.iter().enumerate() {
        if i >= 3 {
            println!("  ... and {} more", preproc_bold.len() - 3);
            break;
        }
        println!("  {}", file.to_filename());
    }

    // Example 2: Find and read confound files
    println!("\n=== Example 2: Confound files ===");
    let confound_files = project.search_files()
        .in_derivatives(true)
        .desc("confounds")
        .suffix("timeseries")
        .extension("tsv")
        .execute()?;

    println!("Found {} confound files", confound_files.len());

    // Read first confound file
    if let Some(confound_file) = confound_files.first() {
        if let Some(path) = &confound_file.path {
            println!("\nReading: {}", confound_file.to_filename());
            let confounds = ConfoundsData::read(path)?;

            // Show available confound columns
            let columns = confounds.column_names();
            println!("Available confounds ({} columns):", columns.len());

            // Group by type
            let motion_params: Vec<_> = columns.iter()
                .filter(|c| c.contains("trans") || c.contains("rot"))
                .collect();
            let compcor: Vec<_> = columns.iter()
                .filter(|c| c.contains("comp_cor"))
                .collect();
            let fd_dvars: Vec<_> = columns.iter()
                .filter(|c| c.contains("framewise") || c.contains("dvars"))
                .collect();

            println!("  Motion parameters: {} columns", motion_params.len());
            if !motion_params.is_empty() {
                println!("    Examples: {:?}", &motion_params[..3.min(motion_params.len())]);
            }

            println!("  CompCor components: {} columns", compcor.len());
            if !compcor.is_empty() {
                println!("    Examples: {:?}", &compcor[..3.min(compcor.len())]);
            }

            println!("  FD/DVARS: {} columns", fd_dvars.len());
            if !fd_dvars.is_empty() {
                println!("    Examples: {:?}", fd_dvars);
            }

            // Get motion parameters for PCA
            if let Ok(motion_data) = confounds.get_motion_parameters() {
                println!("\nMotion parameter matrix: {} timepoints × {} parameters",
                    motion_data.nrows(), motion_data.ncols());

                // Show mean motion
                let means = motion_data.column_mean();
                println!("Mean motion values:");
                for (i, param) in ["trans_x", "trans_y", "trans_z", "rot_x", "rot_y", "rot_z"].iter().enumerate() {
                    if i < means.len() {
                        println!("  {}: {:.4} mm", param, means[i]);
                    }
                }
            }
        }
    }

    // Example 3: Find brain masks
    println!("\n=== Example 3: Brain masks ===");
    let masks = project.search_files()
        .in_derivatives(true)
        .suffix("mask")
        .desc("brain")
        .extension("nii.gz")
        .execute()?;

    println!("Found {} brain masks", masks.len());

    // Group by space
    let mut by_space = std::collections::HashMap::new();
    for mask in &masks {
        if let Some(space) = &mask.space {
            *by_space.entry(space.as_str()).or_insert(0u32) += 1;
        }
    }

    for (space, count) in by_space {
        println!("  Space '{}': {} masks", space, count);
    }

    // Example 4: Find transformation files
    println!("\n=== Example 4: Transformation files ===");
    let transforms = project.search_files()
        .in_derivatives(true)
        .suffix("xfm")
        .extension("h5")
        .execute()?;

    println!("Found {} transformation files", transforms.len());

    // Show transformation types
    for (i, xfm) in transforms.iter().enumerate() {
        if i >= 5 {
            println!("  ... and {} more", transforms.len() - 5);
            break;
        }
        let from_space = xfm.from.as_deref().unwrap_or("unknown");
        let to_space = xfm.to.as_deref().unwrap_or("unknown");
        println!("  {} -> {}: {}", from_space, to_space, xfm.to_filename());
    }

    // Example 5: Find preprocessed anatomical images
    println!("\n=== Example 5: Preprocessed anatomical images ===");
    let anat_preproc = project.search_files()
        .in_derivatives(true)
        .datatype("anat")
        .suffix("preproc")
        .extension("nii.gz")
        .execute()?;

    println!("Found {} preprocessed anatomical images", anat_preproc.len());

    // Group by type (T1w, T2w, etc.)
    let mut by_contrast = std::collections::HashMap::new();
    for anat in &anat_preproc {
        // Extract contrast from suffix or entities
        let contrast = anat.suffix.split('_').next().unwrap_or(&anat.suffix);
        *by_contrast.entry(contrast).or_insert(0u32) += 1;
    }

    for (contrast, count) in by_contrast {
        println!("  {}: {} images", contrast, count);
    }

    // Example 6: Quality control files
    println!("\n=== Example 6: Quality control files ===");

    // Find HTML reports
    let reports = project.search_files()
        .in_derivatives(true)
        .extension("html")
        .execute()?;

    println!("Found {} HTML reports", reports.len());

    // Find figures
    let figures = project.search_files()
        .in_derivatives(true)
        .datatype("figures")
        .execute()?;

    println!("Found {} QC figures", figures.len());

    // Example 7: Working with specific derivative pipeline
    println!("\n=== Example 7: Pipeline-specific files ===");

    // Check for fMRIPrep version info
    let dataset_desc = project.search_files()
        .in_derivatives(true)
        .filename("dataset_description.json")
        .execute()?;

    if let Some(desc_file) = dataset_desc.first() {
        if let Some(path) = &desc_file.path {
            let metadata = SidecarData::read(path)?;

            if let Some(pipeline) = metadata.get("PipelineDescription") {
                println!("Pipeline info found:");
                if let Some(name) = pipeline.get("Name") {
                    println!("  Name: {}", name);
                }
                if let Some(version) = pipeline.get("Version") {
                    println!("  Version: {}", version);
                }
            }
        }
    }

    // Example 8: Find surface files
    println!("\n=== Example 8: Surface files (if available) ===");
    let surfaces = project.search_files()
        .in_derivatives(true)
        .extension("gii")
        .execute()?;

    if surfaces.is_empty() {
        println!("No surface files found (GIFTI format)");
    } else {
        println!("Found {} surface files", surfaces.len());

        // Group by hemisphere
        let mut by_hemi = std::collections::HashMap::new();
        for surf in &surfaces {
            if let Some(hemi) = &surf.hemi {
                *by_hemi.entry(hemi.as_str()).or_insert(0u32) += 1;
            }
        }

        for (hemi, count) in by_hemi {
            println!("  Hemisphere {}: {} files", hemi, count);
        }
    }

    // Summary
    println!("\n=== Derivatives Summary ===");
    let all_derivative_files = project.search_files()
        .in_derivatives(true)
        .execute()?;

    println!("Total files in derivatives: {}", all_derivative_files.len());

    // Count by datatype
    let mut datatypes = std::collections::HashMap::new();
    for file in &all_derivative_files {
        if let Some(dt) = &file.datatype {
            *datatypes.entry(dt.as_str()).or_insert(0u32) += 1;
        }
    }

    println!("By datatype:");
    for (dt, count) in datatypes {
        println!("  {}: {} files", dt, count);
    }

    Ok(())
}

