//! Example of file I/O operations in bids-rust
//! 
//! This example demonstrates how to:
//! - Read event files (TSV format)
//! - Read JSON sidecar metadata
//! - Read confound timeseries
//! - Work with different data formats
//! - Handle errors gracefully

use bids_rust::{BidsProject, EventData, SidecarData, ConfoundsData};
use std::env;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line
    let args: Vec<String> = env::args().collect();
    let dataset_path = if args.len() > 1 {
        Path::new(&args[1])
    } else {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("\nUsing example dataset path...");
        Path::new("./example_dataset")
    };

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = BidsProject::new(dataset_path)?;

    println!("Dataset: {}", project.name);
    println!();

    // Example 1: Reading event files
    println!("=== Example 1: Reading Event Files ===");
    let event_files = project.search_files()
        .suffix("events")
        .extension("tsv")
        .execute()?;

    if event_files.is_empty() {
        println!("No event files found in dataset");
    } else {
        println!("Found {} event files", event_files.len());

        // Read the first event file
        if let Some(event_file) = event_files.first() {
            if let Some(path) = &event_file.path {
                println!("\nReading: {}", event_file.to_filename());

                match EventData::read(path) {
                    Ok(events) => {
                        println!("Successfully read {} events", events.onset.len());

                        // Display event statistics
                        println!("\nEvent Statistics:");
                        println!("  Duration range: {:.2} - {:.2} seconds",
                            events.duration.iter().fold(f64::INFINITY, |a, &b| a.min(b)),
                            events.duration.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b))
                        );

                        // Count trial types
                        let mut trial_counts = std::collections::HashMap::new();
                        for trial in &events.trial_type {
                            *trial_counts.entry(trial.as_str()).or_insert(0u32) += 1;
                        }

                        println!("  Trial types:");
                        for (trial_type, count) in trial_counts {
                            println!("    {}: {} events", trial_type, count);
                        }

                        // Show first few events
                        println!("\n  First 5 events:");
                        for i in 0..5.min(events.onset.len()) {
                            println!("    {:.2}s: {} (duration: {:.2}s)",
                                events.onset[i],
                                events.trial_type[i],
                                events.duration[i]
                            );
                        }

                        // Check for response data
                        if !events.response_time.is_empty() {
                            let valid_responses: Vec<_> = events.response_time.iter()
                                .filter(|&&rt| rt > 0.0)
                                .collect();

                            if !valid_responses.is_empty() {
                                let mean_rt: f64 = valid_responses.iter()
                                    .map(|&&x| x)
                                    .sum::<f64>() / valid_responses.len() as f64;

                                println!("\n  Response data:");
                                println!("    Valid responses: {}/{}", 
                                    valid_responses.len(), 
                                    events.response_time.len()
                                );
                                println!("    Mean RT: {:.0} ms", mean_rt * 1000.0);
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Error reading event file: {}", e);
                    }
                }
            }
        }
    }

    // Example 2: Reading JSON sidecar files
    println!("\n=== Example 2: Reading JSON Sidecar Files ===");
    let json_files = project.search_files()
        .datatype("func")
        .suffix("bold")
        .extension("json")
        .execute()?;

    if json_files.is_empty() {
        println!("No functional JSON sidecar files found");
    } else {
        println!("Found {} JSON sidecar files", json_files.len());

        // Read the first JSON file
        if let Some(json_file) = json_files.first() {
            if let Some(path) = &json_file.path {
                println!("\nReading: {}", json_file.to_filename());

                match SidecarData::read(path) {
                    Ok(sidecar) => {
                        println!("Successfully read JSON metadata");

                        // Display common fields
                        println!("\nImaging Parameters:");
                        if let Some(tr) = sidecar.repetition_time() {
                            println!("  Repetition Time (TR): {} s", tr);
                        }
                        if let Some(te) = sidecar.echo_time() {
                            println!("  Echo Time (TE): {} ms", te * 1000.0);
                        }
                        if let Some(fa) = sidecar.flip_angle() {
                            println!("  Flip Angle: {}°", fa);
                        }
                        if let Some(task) = sidecar.task_name() {
                            println!("  Task Name: {}", task);
                        }
                        if let Some(inst) = sidecar.institution_name() {
                            println!("  Institution: {}", inst);
                        }

                        // Display slice timing if available
                        if let Some(st) = sidecar.slice_timing() {
                            println!("\n  Slice Timing: {} slices", st.len());
                            if !st.is_empty() {
                                println!("    First slice: {:.4} s", st[0]);
                                println!("    Last slice: {:.4} s", st[st.len()-1]);
                            }
                        }

                        // Count total fields
                        println!("\nTotal metadata fields: {}", sidecar.len());
                    }
                    Err(e) => {
                        eprintln!("Error reading JSON file: {}", e);
                    }
                }
            }
        }
    }

    // Example 3: Reading confound files (if derivatives exist)
    if project.has_derivatives {
        println!("\n=== Example 3: Reading Confound Files ===");
        let confound_files = project.search_files()
            .in_derivatives(true)
            .desc("confounds")
            .suffix("timeseries")
            .extension("tsv")
            .execute()?;

        if confound_files.is_empty() {
            println!("No confound files found in derivatives");
        } else {
            println!("Found {} confound files", confound_files.len());

            // Read the first confound file
            if let Some(confound_file) = confound_files.first() {
                if let Some(path) = &confound_file.path {
                    println!("\nReading: {}", confound_file.to_filename());

                    match ConfoundsData::read(path) {
                        Ok(confounds) => {
                            let columns = confounds.column_names();
                            println!("Successfully read confound data");
                            println!("  Columns: {}", columns.len());
                            println!("  Timepoints: {}", confounds.n_timepoints());

                            // Categorize confound types
                            let motion: Vec<_> = columns.iter()
                                .filter(|c| c.contains("trans") || c.contains("rot"))
                                .collect();
                            let tissue: Vec<_> = columns.iter()
                                .filter(|c| c.contains("csf") || c.contains("white_matter") || c.contains("global_signal"))
                                .collect();
                            let compcor: Vec<_> = columns.iter()
                                .filter(|c| c.contains("comp_cor"))
                                .collect();
                            let other: Vec<_> = columns.iter()
                                .filter(|c| c.contains("framewise_displacement") || c.contains("dvars") || c.contains("std_dvars"))
                                .collect();

                            println!("\nConfound Categories:");
                            println!("  Motion parameters: {}", motion.len());
                            println!("  Tissue signals: {}", tissue.len());
                            println!("  CompCor components: {}", compcor.len());
                            println!("  Quality metrics: {}", other.len());

                            // Try to get motion parameters for analysis
                            match confounds.get_motion_parameters() {
                                Ok(motion_data) => {
                                    println!("\nMotion Analysis:");
                                    println!("  Motion matrix: {} × {}", 
                                        motion_data.nrows(), 
                                        motion_data.ncols()
                                    );

                                    // Calculate max displacement
                                    let max_trans = motion_data.columns(0, 3)
                                        .abs()
                                        .max();
                                    let max_rot = motion_data.columns(3, 3)
                                        .abs()
                                        .max();

                                    println!("  Max translation: {:.2} mm", max_trans);
                                    println!("  Max rotation: {:.4} rad ({:.2}°)", 
                                        max_rot, 
                                        max_rot.to_degrees()
                                    );
                                }
                                Err(e) => {
                                    println!("\nCould not extract motion parameters: {}", e);
                                }
                            }

                            // Show framewise displacement if available
                            if let Ok(fd_values) = confounds.get_column("framewise_displacement") {
                                let valid_fd: Vec<_> = fd_values.iter()
                                    .filter(|&&x| !x.is_nan())
                                    .collect();

                                if !valid_fd.is_empty() {
                                    let mean_fd: f64 = valid_fd.iter()
                                        .map(|&&x| x)
                                        .sum::<f64>() / valid_fd.len() as f64;
                                    let max_fd = valid_fd.iter()
                                        .fold(0.0f64, |a, &&b| a.max(b));

                                    println!("\nFramewise Displacement:");
                                    println!("  Mean FD: {:.3} mm", mean_fd);
                                    println!("  Max FD: {:.3} mm", max_fd);

                                    // Count high motion timepoints
                                    let high_motion = valid_fd.iter()
                                        .filter(|&&&x| x > 0.5)
                                        .count();

                                    println!("  Timepoints > 0.5mm: {} ({:.1}%)", 
                                        high_motion,
                                        100.0 * high_motion as f64 / valid_fd.len() as f64
                                    );
                                }
                            }
                        }
                        Err(e) => {
                            eprintln!("Error reading confound file: {}", e);
                        }
                    }
                }
            }
        }
    }

    // Example 4: Batch processing multiple files
    println!("\n=== Example 4: Batch Processing ===");

    // Find all event files for a specific task
    let task_events = project.search_files()
        .suffix("events")
        .task("rest")  // Change to your task
        .extension("tsv")
        .execute()?;

    if !task_events.is_empty() {
        println!("Processing {} event files for task 'rest'", task_events.len());

        let mut total_events = 0;
        let mut all_trial_types = std::collections::HashSet::new();

        for event_file in &task_events {
            if let Some(path) = &event_file.path {
                if let Ok(events) = EventData::read(path) {
                    total_events += events.onset.len();
                    for trial in &events.trial_type {
                        all_trial_types.insert(trial.clone());
                    }
                }
            }
        }

        println!("  Total events across all runs: {}", total_events);
        println!("  Unique trial types: {:?}", all_trial_types);
    }

    // Example 5: Error handling
    println!("\n=== Example 5: Error Handling ===");

    // Try to read a non-existent file
    let fake_path = Path::new("/tmp/non_existent_file.tsv");
    match EventData::read(fake_path) {
        Ok(_) => println!("Unexpectedly succeeded!"),
        Err(e) => println!("Expected error: {}", e),
    }

    // Try to read an incorrectly formatted file
    println!("\nError handling is built into all I/O operations");
    println!("Files are validated according to BIDS specifications");

    Ok(())
}

