//! Quick start example for bids-rust
//! 
//! This example demonstrates the most basic usage of bids-rust.
//! It shows how to load a dataset and perform common operations.

use bids_rust::{BidsProject};
use std::env;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line or use default
    let args: Vec<String> = env::args().collect();
    let dataset_path = if args.len() > 1 {
        Path::new(&args[1])
    } else {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("Example: {} /path/to/my/bids/dataset", args[0]);
        return Ok(());
    };

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = match BidsProject::new(dataset_path) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("Error loading dataset: {}", e);
            eprintln!("\nMake sure the path contains:");
            eprintln!("  - dataset_description.json");
            eprintln!("  - subject directories (sub-*)");
            return Err(e.into());
        }
    };

    // Basic dataset information
    println!("\n=== Dataset Information ===");
    println!("Dataset name: {}", project.name);
    println!("Root path: {}", project.root.display());

    // List participants
    let participants = project.participants();
    println!("\n=== Participants ===");
    println!("Total participants: {}", participants.len());

    if !participants.is_empty() {
        println!("First 5 participants:");
        for (i, participant) in participants.iter().enumerate() {
            if i >= 5 { break; }
            println!("  - sub-{}", participant);
        }
    }

    // Search for files
    println!("\n=== File Search Examples ===");

    // Example 1: Find all anatomical images
    let anat_files = project.search_files()
        .datatype("anat")
        .execute()?;
    println!("Anatomical files: {}", anat_files.len());

    // Example 2: Find functional scans
    let func_files = project.search_files()
        .datatype("func")
        .suffix("bold")
        .execute()?;
    println!("Functional BOLD files: {}", func_files.len());

    // Example 3: Find files for a specific participant
    if let Some(first_participant) = participants.first() {
        let participant_files = project.search_files()
            .subject(first_participant)
            .execute()?;
        println!("Files for sub-{}: {}", first_participant, participant_files.len());
    }

    // Check for derivatives
    if project.has_derivatives {
        println!("\n=== Derivatives ===");
        println!("This dataset has derivatives (preprocessed data)");

        let derivative_files = project.search_files()
            .in_derivatives(true)
            .execute()?;
        println!("Total derivative files: {}", derivative_files.len());
    }

    // Summary
    println!("\n=== Summary ===");
    println!("Successfully loaded BIDS dataset: {}", project.name);
    println!("Ready for analysis!");

    Ok(())
}

